// 2-SAT 通用模板
#include <bits/stdc++.h>
using namespace std;

const int N = 2e5 + 10; // 变量数 * 2
vector<int> g[N], rg[N]; // 原图和反图
int comp[N]; // 每个节点所属的强连通分量
bool used[N];
vector<int> order; // 后序遍历顺序

// 添加蕴含关系: (a -> b)，其中 a, b 为变量编号（0-indexed）
// 若 isTrueA/isTrueB 为 false 表示取反
void addImplication(int a, bool isTrueA, int b, bool isTrueB) {
    int u = a * 2 + !isTrueA; // 假节点
    int v = b * 2 + isTrueB;  // 真节点
    g[u].push_back(v);
    rg[v].push_back(u);
}

// 添加 OR 关系: (a ∨ b)
void addOr(int a, bool isTrueA, int b, bool isTrueB) {
    addImplication(a, !isTrueA, b, isTrueB);
    addImplication(b, !isTrueB, a, isTrueA);
}

// 添加 XOR 关系: (a ⊕ b)
void addXor(int a, bool isTrueA, int b, bool isTrueB) {
    addOr(a, isTrueA, b, isTrueB);
    addOr(a, !isTrueA, b, !isTrueB);
}

// 第一遍 DFS（原图）
void dfs1(int v) {
    used[v] = true;
    for (int to : g[v]) {
        if (!used[to]) dfs1(to);
    }
    order.push_back(v);
}

// 第二遍 DFS（反图）
void dfs2(int v, int cl) {
    comp[v] = cl;
    for (int to : rg[v]) {
        if (comp[to] == -1) dfs2(to, cl);
    }
}

// 主求解函数，返回是否可满足，并填充 assignment
bool solve2SAT(int n, vector<bool>& assignment) {
    fill(used, used + 2 * n, false);
    order.clear();
    for (int i = 0; i < 2 * n; ++i) {
        if (!used[i]) dfs1(i);
    }

    fill(comp, comp + 2 * n, -1);
    for (int i = 0, j = 0; i < 2 * n; ++i) {
        int v = order[2 * n - 1 - i];
        if (comp[v] == -1) dfs2(v, j++);
    }

    assignment.resize(n);
    for (int i = 0; i < n; ++i) {
        if (comp[2 * i] == comp[2 * i + 1]) return false;
        assignment[i] = comp[2 * i] > comp[2 * i + 1];
    }
    return true;
}

// 使用示例
int main() {
    int n, m; // n 个变量，m 个约束
    cin >> n >> m;

    // 建图
    for (int i = 0; i < m; ++i) {
        int a, b; bool ta, tb;
        // 根据输入格式读取约束
        // addOr(a, ta, b, tb); 或其他约束添加函数
    }

    vector<bool> assignment;
    if (solve2SAT(n, assignment)) {
        cout << "YES\n";
        for (bool val : assignment) cout << (val ? "true " : "false ");
    } else {
        cout << "NO\n";
    }
    return 0;
}

