        // 对于构造类问题，按步骤生成合法解
        vector<Point> result;

        // 常见构造策略：
        // - 极角排序后处理
        // - 凸包相关构造
        // - 对称性利用
        // - 增量构造

        // 示例：按x坐标排序后构造
        sort(pts.begin(), pts.end());
