class Blossom { // 带花树算法模板
    int n; // 顶点数
    vector<int> match; // 匹配结果，match[i]表示与i匹配的顶点，-1表示未匹配
    vector<int> parent, base, color, q; // 辅助数组
    vector<vector<int>> g; // 邻接表

    int lca(int a, int b) { // 寻找最近公共祖先
        vector<bool> mark(n, false);
        while (true) {
            a = base[a];
            mark[a] = true;
            if (match[a] == -1) break;
            a = parent[match[a]];
        }
        while (true) {
            b = base[b];
            if (mark[b]) return b;
            b = parent[match[b]];
        }
    }

    void blossom(int a, int b, int l, queue<int>& qt) { // 缩花操作
        while (base[a] != l) {
            parent[a] = b;
            b = match[a];
            if (color[b] == 1) {
                color[b] = 0;
                qt.push(b);
            }
            base[a] = base[b] = l;
            a = parent[b];
        }
    }

    bool bfs(int start) { // 寻找增广路
        fill(parent.begin(), parent.end(), -1);
        fill(color.begin(), color.end(), -1);
        iota(base.begin(), base.end(), 0);
        queue<int> q;
        q.push(start);
        color[start] = 0;
        while (!q.empty()) {
            int u = q.front(); q.pop();
            for (int v : g[u]) {
                if (color[v] == -1) {
                    color[v] = 1;
                    parent[v] = u;
                    if (match[v] == -1) { // 找到增广路
                        while (v != -1) {
                            int pv = parent[v];
                            int ppv = match[pv];
                            match[v] = pv;
                            match[pv] = v;
                            v = ppv;
                        }
                        return true;
                    }
                    color[match[v]] = 0;
                    q.push(match[v]);
                } else if (color[v] == 0 && base[u] != base[v]) {
                    int l = lca(u, v);
                    blossom(u, v, l, q);
                    blossom(v, u, l, q);
                }
            }
        }
        return false;
    }

public:
    Blossom(int n) : n(n), match(n, -1), parent(n), base(n), color(n), g(n) {}

    void addEdge(int u, int v) { // 添加无向边
        g[u].push_back(v);
        g[v].push_back(u);
    }

    int maxMatch() { // 返回最大匹配数
        int res = 0;
        for (int i = 0; i < n; i++) {
            if (match[i] == -1) {
                if (bfs(i)) res++;
            }
        }
        return res;
    }

    vector<pair<int, int>> getMatches() { // 获取所有匹配边
        vector<pair<int, int>> res;
        for (int i = 0; i < n; i++) {
            if (match[i] != -1 && i < match[i]) {
                res.emplace_back(i, match[i]);
            }
        }
        return res;
    }
};

二分图匹配问题通常使用匈牙利算法（Hungarian Algorithm）或最大流算法（如Dinic、Hopcroft-Karp）解决。以下是匈牙利算法（DFS实现）的通用模板：

```cpp
#include <bits/stdc++.h>
using namespace std;

const int MAXN = 1005; // 根据题目调整
vector<int> g[MAXN];   // 邻接表，存储左部到右部的边
int matchR[MAXN];      // 右部匹配的左部点编号，-1表示未匹配
bool vis[MAXN];        // DFS访问标记

bool dfs(int u) {
    for (int v : g[u]) {
        if (vis[v]) continue;
        vis[v] = true;
        if (matchR[v] == -1 || dfs(matchR[v])) {
            matchR[v] = u;
            return true;
        }
    }
    return false;
}

int hungarian(int n_left, int n_right) {
    memset(matchR, -1, sizeof(matchR));
    int match_cnt = 0;
    for (int u = 0; u < n_left; ++u) {
        memset(vis, 0, sizeof(vis));
        if (dfs(u)) match_cnt++;
    }
    return match_cnt;
}
```

对于更复杂的问题（如带权匹配、最小点覆盖、最大独立集等），可能需要扩展为KM算法（Kuhn-Munkres）或转化为最大流模型。

// 网络流基础模板（Dinic算法）
template<typename T>
struct Flow {
    struct Edge { int to; T cap; int rev; };
    vector<vector<Edge>> g;
    vector<int> level, iter;
    Flow(int n) : g(n), level(n), iter(n) {}
    void add_edge(int from, int to, T cap) {
        g[from].push_back({to, cap, (int)g[to].size()});
        g[to].push_back({from, 0, (int)g[from].size()-1});
    }
    void bfs(int s) {
        fill(level.begin(), level.end(), -1);
        queue<int> q; q.push(s); level[s] = 0;
        while(!q.empty()) {
            int v = q.front(); q.pop();
            for(auto &e : g[v]) {
                if(e.cap > 0 && level[e.to] < 0) {
                    level[e.to] = level[v] + 1;
                    q.push(e.to);
                }
            }
        }
    }
    T dfs(int v, int t, T f) {
        if(v == t) return f;
        for(int &i = iter[v]; i < g[v].size(); i++) {
            Edge &e = g[v][i];
            if(e.cap > 0 && level[v] < level[e.to]) {
                T d = dfs(e.to, t, min(f, e.cap));
                if(d > 0) {
                    e.cap -= d;
                    g[e.to][e.rev].cap += d;
                    return d;
                }
            }
        }
        return 0;
    }
    T max_flow(int s, int t) {
        T flow = 0;
        while(true) {
            bfs(s);
            if(level[t] < 0) return flow;
            fill(iter.begin(), iter.end(), 0);
            T f;
            while((f = dfs(s, t, numeric_limits<T>::max())) > 0) {
                flow += f;
            }
        }
    }
};

// 二分图匹配模板（基于网络流）
int bipartite_matching(int L, int R, vector<pair<int,int>> &edges) {
    int S = L + R, T = S + 1;
    Flow<int> flow(L + R + 2);
    for(int i = 0; i < L; i++) flow.add_edge(S, i, 1);
    for(int i = 0; i < R; i++) flow.add_edge(L + i, T, 1);
    for(auto &[u, v] : edges) {
        flow.add_edge(u, L + v, 1);
    }
    return flow.max_flow(S, T);
}

// 最小路径覆盖模板（DAG）
int min_path_cover(int n, vector<pair<int,int>> &edges) {
    // 拆点：左部点1..n，右部点n+1..2n
    int S = 2*n, T = 2*n + 1;
    Flow<int> flow(2*n + 2);
    for(int i = 0; i < n; i++) {
        flow.add_edge(S, i, 1);
        flow.add_edge(n + i, T, 1);
    }
    for(auto &[u, v] : edges) {
        flow.add_edge(u, n + v, 1);
    }
    return n - flow.max_flow(S, T);
}

// 关键建模步骤框架
void solve() {
    // 1. 识别问题类型
    //    - 最大匹配/最小点覆盖/最大独立集（二分图）
    //    - 最小路径覆盖（DAG）
    //    - 有上下界的流
    //    - 最小割建模

    // 2. 构建网络流图
    //    - 确定节点类型（原图节点/拆点/超级源汇）
    //    - 设置边的容量（通常为1或INF）
    //    - 注意有向边的方向

    // 3. 运行最大流/最小割算法
    //    - 根据问题选择源点S和汇点T
    //    - 调用max_flow(S, T)

    // 4. 从流中提取答案
    //    - 最大匹配数 = 最大流值
    //    - 最小路径覆盖数 = n - 最大流值
    //    - 通过残量网络构造具体方案
}

// 最大流-最小割通用模板
// 核心：Dinic算法或ISAP算法
#include <bits/stdc++.h>
using namespace std;

struct MaxFlow {
    struct Edge {
        int to, rev;
        long long cap;
        Edge(int to, int rev, long long cap) : to(to), rev(rev), cap(cap) {}
    };

    int n;
    vector<vector<Edge>> g;
    vector<int> level, iter;

    MaxFlow(int n) : n(n), g(n), level(n), iter(n) {}

    void addEdge(int from, int to, long long cap) {
        g[from].emplace_back(to, g[to].size(), cap);
        g[to].emplace_back(from, g[from].size() - 1, 0); // 有向图
        // 对于无向图：g[to].emplace_back(from, g[from].size() - 1, cap);
    }

    void bfs(int s) {
        fill(level.begin(), level.end(), -1);
        queue<int> q;
        level[s] = 0;
        q.push(s);
        while (!q.empty()) {
            int v = q.front(); q.pop();
            for (auto &e : g[v]) {
                if (e.cap > 0 && level[e.to] < 0) {
                    level[e.to] = level[v] + 1;
                    q.push(e.to);
                }
            }
        }
    }

    long long dfs(int v, int t, long long f) {
        if (v == t) return f;
        for (int &i = iter[v]; i < g[v].size(); i++) {
            Edge &e = g[v][i];
            if (e.cap > 0 && level[v] < level[e.to]) {
                long long d = dfs(e.to, t, min(f, e.cap));
                if (d > 0) {
                    e.cap -= d;
                    g[e.to][e.rev].cap += d;
                    return d;
                }
            }
        }
        return 0;
    }

    long long maxFlow(int s, int t) {
        long long flow = 0;
        while (true) {
            bfs(s);
            if (level[t] < 0) return flow;
            fill(iter.begin(), iter.end(), 0);
            long long f;
            while ((f = dfs(s, t, 1e18)) > 0) {
                flow += f;
            }
        }
    }

    // 最小割：在maxFlow之后，从源点s可达的点集合为S，不可达的为T
    // 所有从S到T的边的容量和即为最小割值
    vector<int> minCutSet(int s) {
        bfs(s);
        vector<int> res;
        for (int i = 0; i < n; i++) {
            if (level[i] >= 0) res.push_back(i);
        }
        return res;
    }
};

