// 方法1：DP递推（常用于计数、最优值问题）
ll solveDP() {
    // 初始化：从每个节点开始，只访问自己的状态
    for (int i = 0; i < n; i++) {
        dp[1 << i][i] = 1; // 或初始代价等
    }

    for (int mask = 1; mask < (1 << n); mask++) {
        for (int u = 0; u < n; u++) {
            if (!(mask & (1 << u))) continue;
            if (dp[mask][u] == 0) continue; // 无效状态

            for (int v : adj[u]) {
                if (mask & (1 << v)) {
                    // 可能形成环，根据题目处理
                    // 例如：计数简单环 if (v == startNode && __builtin_popcount(mask) >= 3)
                } else {
                    // 扩展状态
                    int newMask = mask | (1 << v);
                    dp[newMask][v] += dp[mask][u]; // 计数
                    // 或 dp[newMask][v] = min(dp[newMask][v], dp[mask][u] + w);
                }
            }
        }
    }

    // 根据题目要求聚合结果
    ll ans = 0;
    for (int mask = 1; mask < (1 << n); mask++) {
        for (int u = 0; u < n; u++) {
            // 例如：统计所有哈密顿路径或环
            if (__builtin_popcount(mask) == n) {
                ans += dp[mask][u];
            }
        }
    }
    return ans;
}

// 方法2：BFS/DFS状态搜索（常用于可达性、最短步数问题）
int solveBFS() {
    queue<pair<int, int>> q; // (mask, node)
    vector<vector<int>> dist(1 << n, vector<int>(n, -1));

    // 初始状态：可能多个起点
    int startMask = 0;
    for (int i : startNodes) {
        startMask |= (1 << i);
        dist[startMask][i] = 0;
        q.push({startMask, i});
    }

    while (!q.empty()) {
        auto [mask, u] = q.front(); q.pop();
        for (int v : adj[u]) {
            int newMask = mask | (1 << v);
            if (dist[newMask][v] == -1) {
                dist[newMask][v] = dist[mask][u] + 1;
                q.push({newMask, v});
            }
        }
    }

    // 寻找目标状态
    int targetMask = (1 << n) - 1; // 或特定mask
    int ans = INF;
    for (int u = 0; u < n; u++) {
        if (dist[targetMask][u] != -1) {
            ans = min(ans, dist[targetMask][u]);
        }
    }
    return ans;
}

