const int N = 1e5 + 5; // 根据题目调整
vector<int> g[N];      // 邻接表
int n, m;              // 节点数、边数
int vis[N];            // 访问标记，0未访问，1访问中，2已访问
int parent[N];         // 用于记录父节点/前驱
int in_cycle[N];       // 标记节点是否在环上
int depth[N];          // 深度/距离
vector<int> cycle;     // 存储环上的节点

// 1. 寻找环（适用于有向/无向基环树）
bool dfs_find_cycle(int u, int p) {
    vis[u] = 1;
    parent[u] = p;
    for (int v : g[u]) {
        if (v == p) continue; // 无向图防回父
        if (vis[v] == 0) {
            if (dfs_find_cycle(v, u)) return true;
        } else if (vis[v] == 1) {
            // 找到环，回溯记录环上节点
            int cur = u;
            while (cur != v) {
                cycle.push_back(cur);
                in_cycle[cur] = 1;
                cur = parent[cur];
            }
            cycle.push_back(v);
            in_cycle[v] = 1;
            return true;
        }
    }
    vis[u] = 2;
    return false;
}

// 2. 处理树部分（从环上节点向外DFS/BFS）
void dfs_tree(int u, int p) {
    for (int v : g[u]) {
        if (v == p || in_cycle[v]) continue;
        depth[v] = depth[u] + 1; // 或其他需要维护的信息
        dfs_tree(v, u);
    }
}

// 3. 功能图（每个节点出度为1）的环检测
void functional_graph_cycle(int start, vector<int>& next) {
    int u = start;
    while (vis[u] == 0) {
        vis[u] = 1;
        u = next[u];
    }
    // 此时u在环上，可记录环
    if (vis[u] == 1) {
        int v = u;
        do {
            cycle.push_back(v);
            in_cycle[v] = 1;
            v = next[v];
        } while (v != u);
    }
    // 重置标记（可选）
    u = start;
    while (vis[u] == 1) {
        vis[u] = 2;
        u = next[u];
    }
}

// 4. 拓扑排序去除树部分，留下环（适用于有向基环树）
void topological_trim() {
    queue<int> q;
    vector<int> indeg(n + 1, 0);
    for (int u = 1; u <= n; u++)
        for (int v : g[u]) indeg[v]++;
    for (int u = 1; u <= n; u++)
        if (indeg[u] == 0) q.push(u);
    while (!q.empty()) {
        int u = q.front(); q.pop();
        for (int v : g[u]) {
            indeg[v]--;
            if (indeg[v] == 0) q.push(v);
        }
    }
    // 剩余 indeg > 0 的节点在环上
    for (int u = 1; u <= n; u++)
        if (indeg[u] > 0) in_cycle[u] = 1;
}

