// 欧拉路径/回路模板
bool hasEulerPath() {
    // 1. 计算所有顶点的度数
    vector<int> degree(n, 0);
    for (auto &edge : edges) {
        degree[edge.u]++;
        degree[edge.v]++;
    }

    // 2. 检查连通性（使用DFS/BFS/并查集）
    if (!isConnected()) return false;

    // 3. 统计奇度数顶点数量
    int oddCount = 0;
    for (int d : degree) {
        if (d % 2 == 1) oddCount++;
    }

    // 4. 判断欧拉路径/回路存在性
    // 欧拉回路：所有顶点度数为偶数
    // 欧拉路径：恰好0或2个奇度数顶点
    return oddCount == 0 || oddCount == 2;
}

// Hierholzer算法求欧拉路径
vector<int> findEulerPath() {
    stack<int> stk;
    vector<int> path;

    // 选择起点：欧拉回路任意起点，欧拉路径从奇度数顶点开始
    int start = findStartVertex();
    stk.push(start);

    while (!stk.empty()) {
        int u = stk.top();
        if (!adj[u].empty()) {
            int v = adj[u].back();
            adj[u].pop_back();
            // 无向图需删除反向边
            removeReverseEdge(u, v);
            stk.push(v);
        } else {
            path.push_back(u);
            stk.pop();
        }
    }
    reverse(path.begin(), path.end());
    return path;
}

// 哈密顿路径模板（通常需要状态压缩DP）
int hamiltonianPath() {
    // dp[mask][last] 表示经过mask中的顶点，最后在last的最小代价
    vector<vector<int>> dp(1 << n, vector<int>(n, INF));

    // 初始化
    for (int i = 0; i < n; i++) {
        dp[1 << i][i] = 0;
    }

    // 状态转移
    for (int mask = 0; mask < (1 << n); mask++) {
        for (int last = 0; last < n; last++) {
            if (dp[mask][last] == INF) continue;
            for (int next = 0; next < n; next++) {
                if (mask >> next & 1) continue;
                int newMask = mask | (1 << next);
                dp[newMask][next] = min(dp[newMask][next], 
                    dp[mask][last] + dist[last][next]);
            }
        }
    }

    // 寻找完整路径的最小代价
    int ans = INF;
    int fullMask = (1 << n) - 1;
    for (int i = 0; i < n; i++) {
        ans = min(ans, dp[fullMask][i]);
    }
    return ans;
}

