const int dy8[] = {1, 1, 0, -1, -1, -1, 0, 1};

// 网格边界检查函数
bool inGrid(int x, int y, int n, int m) {
    return x >= 0 && x < n && y >= 0 && y < m;
}

// BFS 模板（最短路径/可达性）
int bfs(vector<string>& grid, pair<int,int> start, pair<int,int> target) {
    int n = grid.size(), m = grid[0].size();
    vector<vector<int>> dist(n, vector<int>(m, -1));
    queue<pair<int,int>> q;

    dist[start.first][start.second] = 0;
    q.push(start);

    while (!q.empty()) {
        auto [x, y] = q.front(); q.pop();
        if (make_pair(x, y) == target) return dist[x][y];

        for (int d = 0; d < 4; d++) {
            int nx = x + dx4[d], ny = y + dy4[d];
            if (inGrid(nx, ny, n, m) && grid[nx][ny] != '#' && dist[nx][ny] == -1) {
                dist[nx][ny] = dist[x][y] + 1;
                q.push({nx, ny});
            }
        }
    }
    return -1; // 不可达
}

// DFS 模板（连通块/回溯）
void dfs(vector<string>& grid, vector<vector<bool>>& vis, int x, int y) {
    int n = grid.size(), m = grid[0].size();
    vis[x][y] = true;

    for (int d = 0; d < 4; d++) {
        int nx = x + dx4[d], ny = y + dy4[d];
        if (inGrid(nx, ny, n, m) && !vis[nx][ny] && grid[nx][ny] != '#') {
            dfs(grid, vis, nx, ny);
        }
    }
}

// 多源 BFS 模板（多个起点同时扩散）
vector<vector<int>> multiSourceBfs(vector<string>& grid, vector<pair<int,int>>& sources) {
    int n = grid.size(), m = grid[0].size();
    vector<vector<int>> dist(n, vector<int>(m, -1));
    queue<pair<int,int>> q;

    for (auto [x, y] : sources) {
        dist[x][y] = 0;
        q.push({x, y});
    }

    while (!q.empty()) {
        auto [x, y] = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nx = x + dx4[d], ny = y + dy4[d];
            if (inGrid(nx, ny, n, m) && grid[nx][ny] != '#' && dist[nx][ny] == -1) {
                dist[nx][ny] = dist[x][y] + 1;
                q.push({nx, ny});
            }
        }
    }
    return dist;
}

// 状态 BFS 模板（携带额外状态，如钥匙、方向等）
struct State {
