class TwoSAT {
    int n; // 变量数量
    vector<vector<int>> adj, radj; // 原图和反图
    vector<bool> visited, assignment;
    vector<int> order, comp;

    void dfs1(int u) { // 第一次DFS获取逆后序
        visited[u] = true;
        for (int v : adj[u]) if (!visited[v]) dfs1(v);
        order.push_back(u);
    }

    void dfs2(int u, int cl) { // 第二次DFS标记SCC
        comp[u] = cl;
        for (int v : radj[u]) if (comp[v] == -1) dfs2(v, cl);
    }

    bool solve() {
        // 求SCC
        for (int i = 0; i < 2*n; i++) if (!visited[i]) dfs1(i);
        reverse(order.begin(), order.end());
        int cnt = 0;
        for (int u : order) if (comp[u] == -1) dfs2(u, cnt++);

        // 检查可行性
        for (int i = 0; i < n; i++) {
            if (comp[i] == comp[i+n]) return false;
            assignment[i] = comp[i] > comp[i+n]; // 拓扑序大的值赋为真
        }
        return true;
    }

    void add_clause(int a, bool na, int b, bool nb) {
        // 将变量a（na为真表示取反）和b（nb为真表示取反）加入子句
        int u = a + (na ? n : 0), v = b + (nb ? n : 0);
        adj[u^1].push_back(v); // ¬a → b
        adj[v^1].push_back(u); // ¬b → a
        // 同时更新反图（Kosaraju用）
    }
}

