// 点双连通分量与割点通用模板（基于邻接表，无向图）
#include <bits/stdc++.h>
using namespace std;
const int N = 1e5 + 10, M = 2e5 + 10; // 根据题目调整
vector<int> g[N]; // 原图邻接表
int dfn[N], low[N], stk[N], bcc_id[N], is_cut[N];
vector<int> bcc[N]; // 存储每个点双中的顶点（可选）
int dfs_clock = 0, top = 0, bcc_cnt = 0;
// Tarjan 求割点和点双连通分量（基于顶点）
void tarjan(int u, int fa) {
    dfn[u] = low[u] = ++dfs_clock;
    stk[++top] = u;
    int child = 0;
    for (int v : g[u]) {
        if (!dfn[v]) {
            child++;
            tarjan(v, u);
            low[u] = min(low[u], low[v]);
            if (low[v] >= dfn[u]) { // u 是割点，找到一个点双
                is_cut[u] = 1;
                bcc_cnt++;
                int x;
                do {
                    x = stk[top--];
                    bcc[bcc_cnt].push_back(x); // 记录点双中的点
                    bcc_id[x] = bcc_cnt;       // 可选：记录点所属点双（割点属于多个）
                } while (x != v);
                bcc[bcc_cnt].push_back(u); // 割点也加入当前点双
            }
        } else if (v != fa && dfn[v] < dfn[u]) {
            low[u] = min(low[u], dfn[v]);
        }
    }
    if (fa == 0 && child < 2) is_cut[u] = 0; // 根节点特判
}
// 建圆方树（点数最多 2N，因为原图每个点双变成一个方点）
