int dfn[N], low[N], timestamp; // Tarjan数组
bool is_bridge[M]; // 标记每条边是否为桥，注意无向图边编号技巧
int dcc_id[N], dcc_cnt; // 每个点所属的边双编号，边双数量
stack<int> stk; // 用于存储边双中的点（部分写法）

// Tarjan求桥（无向图）
void tarjan(int u, int from_edge) {
    dfn[u] = low[u] = ++timestamp;
    stk.push(u); // 压栈用于求边双
    for (int i = 0; i < g[u].size(); i++) {
        int v = g[u][i];
        if (!dfn[v]) {
            tarjan(v, i); // i作为边的编号标识
            low[u] = min(low[u], low[v]);
            if (low[v] > dfn[u]) { // 判断桥
                is_bridge[i] = is_bridge[i ^ 1] = true; // 无向图双向标记
            }
        } else if (i != (from_edge ^ 1)) { // 不是反向边
            low[u] = min(low[u], dfn[v]);
        }
    }
    // 求边双连通分量（栈写法）
    if (low[u] == dfn[u]) {
        ++dcc_cnt;
        int y;
        do {
            y = stk.top(); stk.pop();
            dcc_id[y] = dcc_cnt;
        } while (y != u);
    }
}

// 构建边双缩点后的树（森林）
vector<int> tree[N]; // 缩点后的树
void build_tree() {
    for (int u = 1; u <= n; u++) {
        for (int v : g[u]) {
            if (dcc_id[u] != dcc_id[v]) {
                tree[dcc_id[u]].push_back(dcc_id[v]);
            }
        }
    }
    // 通常需要去重，因为可能有多条边连接两个边双
}

