// 分层图 - 状态增强最短路通用模板
#include <bits/stdc++.h>
using namespace std;

const int MAXN = 1e5 + 5;
const int MAXK = 10;          // 状态维度，根据题目调整
const long long INF = 1e18;

struct Edge {
    int to, w;
    Edge(int _to, int _w) : to(_to), w(_w) {}
};

struct Node {
    int u, state;            // 当前节点和状态
    long long dist;
    Node(int _u, int _s, long long _d) : u(_u), state(_s), dist(_d) {}
    bool operator>(const Node& other) const {
        return dist > other.dist;
    }
};

vector<Edge> graph[MAXN];
long long dist[MAXN][MAXK];   // dist[i][s] 表示到达节点i且状态为s的最短距离
bool vis[MAXN][MAXK];
int n, m, k;                  // k为状态数量

// 状态转移函数：根据当前状态和边权计算新状态
int nextState(int curState, int edgeW) {
    // 根据具体题目实现状态转移规则
    // 例如：curState表示已使用特殊边的次数，edgeW表示边权
    return curState; // 示例
}

void dijkstra(int start) {
    for (int i = 1; i <= n; i++)
        for (int s = 0; s <= k; s++)
            dist[i][s] = INF, vis[i][s] = false;

    priority_queue<Node, vector<Node>, greater<Node>> pq;
    dist[start][0] = 0;       // 初始状态通常为0
    pq.push(Node(start, 0, 0));

    while (!pq.empty()) {
        Node cur = pq.top(); pq.pop();
        int u = cur.u, state = cur.state;
        if (vis[u][state]) continue;
        vis[u][state] = true;

        for (Edge& e : graph[u]) {
            int v = e.to;
            int newState = nextState(state, e.w);
            long long newDist = dist[u][state] + e.w; // 根据题目可能修改

            if (newDist < dist[v][newState]) {
                dist[v][newState] = newDist;
                pq.push(Node(v, newState, newDist));
            }
        }
    }
}

int main() {
    // 1. 读入n,m,k等参数
