// 多源-多目标-第K短路通用模板
#include <bits/stdc++.h>
using namespace std;

typedef long long ll;
typedef pair<ll, int> pli;

struct Edge {
    int to;
    ll w;
};

// 核心函数：K短路求解
vector<ll> kth_shortest_paths(int n, vector<vector<Edge>>& graph, vector<int>& sources, vector<int>& targets, int k) {
    // 1. 多源最短路预处理（从所有目标点反向Dijkstra）
    vector<ll> dist(n + 1, LLONG_MAX);
    priority_queue<pli, vector<pli>, greater<pli>> pq;
    for (int t : targets) {
        dist[t] = 0;
        pq.push({0, t});
    }
    while (!pq.empty()) {
        auto [d, u] = pq.top(); pq.pop();
        if (d > dist[u]) continue;
        for (auto& e : graph[u]) {
            ll nd = d + e.w;
            if (nd < dist[e.to]) {
                dist[e.to] = nd;
                pq.push({nd, e.to});
            }
        }
    }

    // 2. A*搜索（从源点到目标点）
    vector<ll> ans;
    priority_queue<pli, vector<pli>, greater<pli>> astar;
    for (int s : sources) {
        if (dist[s] != LLONG_MAX) {
            astar.push({dist[s], s}); // 初始估价 = 启发值
        }
    }

    while (!astar.empty() && ans.size() < k) {
        auto [f, u] = astar.top(); astar.pop();
        // 到达目标点处理（根据题目需求调整）
        if (find(targets.begin(), targets.end(), u) != targets.end()) {
            ans.push_back(f); // 实际路径长度
        }
        // 扩展邻居（根据具体图结构调整）
        for (auto& e : graph[u]) {
            ll g = f - dist[u] + e.w; // 实际已走距离
            ll h = dist[e.to];        // 启发值
            if (h != LLONG_MAX) {
                astar.push({g + h, e.to});
            }
        }
    }

    // 3. 处理不足K条的情况
    while (ans.size() < k) {
        ans.push_back(-1); // 或根据题目要求返回特定值
    }
    return ans;
}

