// 1. 预处理函数（DFS/LCA初始化）
void dfs_preprocess(int u, int p, int d) {
    depth[u] = d;
    parent[u][0] = p;
    for (int i = 1; i < 20; i++) {
        parent[u][i] = parent[parent[u][i-1]][i-1];
    }
    for (int v : adj[u]) {
        if (v != p) {
            dfs_preprocess(v, u, d+1);
        }
    }
}

// 2. LCA查询函数
int lca(int u, int v) {
    if (depth[u] < depth[v]) swap(u, v);
    for (int i = 19; i >= 0; i--) {
        if (depth[u] - (1<<i) >= depth[v]) {
            u = parent[u][i];
        }
    }
    if (u == v) return u;
    for (int i = 19; i >= 0; i--) {
        if (parent[u][i] != parent[v][i]) {
            u = parent[u][i];
            v = parent[v][i];
        }
    }
    return parent[u][0];
}

// 3. 树上两点距离计算
int tree_distance(int u, int v) {
    int anc = lca(u, v);
    return depth[u] + depth[v] - 2 * depth[anc];
}

// 4. 直径计算（两次DFS/BFS）
pair<int, int> find_farthest(int start) {
    memset(dist, -1, sizeof(dist));
    queue<int> q;
    q.push(start);
    dist[start] = 0;
    int farthest = start;
    while (!q.empty()) {
        int u = q.front(); q.pop();
        farthest = u;
        for (int v : adj[u]) {
            if (dist[v] == -1) {
                dist[v] = dist[u] + 1;
                q.push(v);
            }
        }
    }
    return {farthest, dist[farthest]};
}

