// 树的分治与重构通用模板
#include <bits/stdc++.h>
using namespace std;

const int N = 2e5 + 10;
vector<int> g[N]; // 邻接表
bool vis[N]; // 标记已删除的节点
int sz[N]; // 子树大小
int mx[N]; // 最大子树大小

// 计算子树大小
void dfs_size(int u, int fa) {
    sz[u] = 1;
    mx[u] = 0;
    for (int v : g[u]) {
        if (v == fa || vis[v]) continue;
        dfs_size(v, u);
        sz[u] += sz[v];
        mx[u] = max(mx[u], sz[v]);
    }
}

// 寻找重心
int find_centroid(int u, int fa, int total) {
    mx[u] = max(mx[u], total - sz[u]);
    int centroid = u;
    for (int v : g[u]) {
        if (v == fa || vis[v]) continue;
        int cand = find_centroid(v, u, total);
        if (mx[cand] < mx[centroid]) centroid = cand;
    }
    return centroid;
}

// 处理经过重心u的路径/子树信息
void collect(int u, int fa, int depth, vector<int>& info) {
    info.push_back(depth); // 根据具体问题收集信息
    for (int v : g[u]) {
        if (v == fa || vis[v]) continue;
        collect(v, u, depth + 1, info);
    }
}

// 分治主函数
void divide(int u) {
    dfs_size(u, -1);
    int centroid = find_centroid(u, -1, sz[u]);
    vis[centroid] = true;

    // 处理所有经过重心的路径
    vector<int> total_info; // 总信息
    for (int v : g[centroid]) {
        if (vis[v]) continue;
        vector<int> sub_info;
        collect(v, centroid, 1, sub_info);
        // 1. 计算当前子树与之前子树的贡献
        // 2. 将当前子树信息合并到总信息中
        total_info.insert(total_info.end(), sub_info.begin(), sub_info.end());
    }

    // 递归处理剩余部分
    for (int v : g[centroid]) {
        if (vis[v]) continue;
        divide(v);
    }
}

