// 树节点定义
type TreeNode struct {
    Val   int
    Left  *TreeNode
    Right *TreeNode
}

// 递归前序遍历
func preorderTraversal(root *TreeNode) []int {
    var res []int
    var dfs func(*TreeNode)
    dfs = func(node *TreeNode) {
        if node == nil {
            return
        }
        res = append(res, node.Val) // 访问节点
        dfs(node.Left)
        dfs(node.Right)
    }
    dfs(root)
    return res
}

// 迭代前序遍历（栈实现）
func preorderTraversalIterative(root *TreeNode) []int {
    var res []int
    if root == nil {
        return res
    }
    stack := []*TreeNode{root}
    for len(stack) > 0 {
        node := stack[len(stack)-1]
        stack = stack[:len(stack)-1]
        res = append(res, node.Val)
        if node.Right != nil {
            stack = append(stack, node.Right)
        }
        if node.Left != nil {
            stack = append(stack, node.Left)
        }
    }
    return res
}

// 层序遍历（队列实现）
func levelOrder(root *TreeNode) [][]int {
    var res [][]int
    if root == nil {
        return res
    }
    queue := []*TreeNode{root}
    for len(queue) > 0 {
        levelSize := len(queue)
        levelVals := []int{}
        for i := 0; i < levelSize; i++ {
            node := queue[0]
            queue = queue[1:]
            levelVals = append(levelVals, node.Val)
            if node.Left != nil {
                queue = append(queue, node.Left)
            }
            if node.Right != nil {
                queue = append(queue, node.Right)
            }
        }
        res = append(res, levelVals)
    }
    return res
}

// 树的高度（深度）
func maxDepth(root *TreeNode) int {
    if root == nil {
        return 0
    }
    leftDepth := maxDepth(root.Left)
    rightDepth := maxDepth(root.Right)
    return max(leftDepth, rightDepth) + 1
}

// 树的节点数
func countNodes(root *TreeNode) int {
    if root == nil {
        return 0
    }
    return 1 + countNodes(root.Left) + countNodes(root.Right)
}

// 辅助函数：最大值
func max(a, b int) int {
    if a > b {
        return a
    }
    return b
}

// 核心框架：基于并查集（DSU）的Kruskal算法，结合图论模型转换
#include <bits/stdc++.h>
using namespace std;

// 1. 数据结构定义
struct Edge {
    int u, v;
    long long w;
    bool operator<(const Edge& other) const {
        return w < other.w;
    }
};

class DSU {
    vector<int> parent, rank;
public:
    DSU(int n) {
        parent.resize(n);
        rank.resize(n, 0);
        for (int i = 0; i < n; i++) parent[i] = i;
    }
    int find(int x) {
        if (parent[x] != x) parent[x] = find(parent[x]);
        return parent[x];
    }
    bool unite(int x, int y) {
        x = find(x); y = find(y);
        if (x == y) return false;
        if (rank[x] < rank[y]) swap(x, y);
        parent[y] = x;
        if (rank[x] == rank[y]) rank[x]++;
        return true;
    }
};

// 2. 模型转换函数（根据题目具体实现）
// 示例：将原图转换为包含所有关键点（如传送门）的新图
vector<Edge> transformGraph(int n, vector<Edge>& edges, vector<int>& portals) {
    // Step 1: 从所有关键点运行多源最短路（Dijkstra），得到每个点到最近关键点的距离
    vector<long long> dist(n, LLONG_MAX);
    priority_queue<pair<long long, int>> pq;
    for (int p : portals) {
        dist[p] = 0;
        pq.push({0, p});
    }
    while (!pq.empty()) {
        auto [d, u] = pq.top(); pq.pop();
        d = -d;
        if (d > dist[u]) continue;
        // 遍历原图边（需根据输入格式调整）
        for (auto& e : adj[u]) {
            int v = e.first;
            long long w = e.second;
            if (dist[v] > dist[u] + w) {
                dist[v] = dist[u] + w;
                pq.push({-dist[v], v});
            }
        }
    }

    // Step 2: 构建新图的边
    vector<Edge> newEdges;
    for (auto& e : edges) {
        // 原边(u,v,w)转换为连接u和v所属最近关键点的边
        // 新边权重 = dist[u] + w + dist[v]
        long long newW = dist[e.u] + e.w + dist[e.v];
        newEdges.push_back({e.u, e.v, newW});
    }
    // 也可能需要添加关键点之间的直接边
    return newEdges;
}

// 3. 主求解函数
long long solve(int n, vector<Edge>& edges, vector<int>& portals) {
    // 模型转换
    vector<Edge> newEdges = transformGraph(n, edges, portals);

    // Kruskal求MST
    sort(newEdges.begin(), newEdges.end());
    DSU dsu(n);
    long long ans = 0;
    for (auto& e : newEdges) {
        if (dsu.unite(e.u, e.v)) {
            ans += e.w;
        }
    }
    return ans;
}

