#include <bits/stdc++.h>
using namespace std;

// 数据结构定义
struct DSU {
    vector<int> parent, size;
    DSU(int n) {
        parent.resize(n);
        size.resize(n, 1);
        iota(parent.begin(), parent.end(), 0);
    }
    int find(int x) {
        return parent[x] == x ? x : parent[x] = find(parent[x]);
    }
    bool unite(int x, int y) {
        x = find(x);
        y = find(y);
        if (x == y) return false;
        if (size[x] < size[y]) swap(x, y);
        parent[y] = x;
        size[x] += size[y];
        return true;
    }
    bool connected(int x, int y) {
        return find(x) == find(y);
    }
};

// 核心函数：按位贪心构建最小生成树
long long xorMST(int n, vector<pair<int, pair<int, int>>>& edges) {
    // edges: {weight, {u, v}}
    sort(edges.begin(), edges.end());
    DSU dsu(n);
    long long ans = 0;
    for (auto& [w, uv] : edges) {
        auto [u, v] = uv;
        if (dsu.unite(u, v)) {
            ans += w;
        }
    }
    return ans;
}

