    }

    // 通用解题框架
    // 1. 位运算贪心：从高位到低位考虑
    long long answer = 0;
    for (int bit = 30; bit >= 0; bit--) {
        // 2. 构建当前位为0的边集
        vector<pair<int, pair<int, int>>> candidateEdges;
        for (auto& [w, uv] : edges) {
            if (!(w >> bit & 1)) {
                candidateEdges.push_back({w, uv});
            }
        }

        // 3. 检查是否能形成连通图
        DSU tempDSU(n);
        int components = n;
        for (auto& [w, uv] : candidateEdges) {
            auto [u, v] = uv;
            if (tempDSU.unite(u, v)) {
                components--;
            }
        }

        // 4. 根据连通性决定是否添加当前位
        if (components == 1) {
            // 可以不用当前位，更新边集
            edges = move(candidateEdges);
        } else {
            // 必须使用当前位，累加到答案
            answer |= (1LL << bit);
        }
    }

    // 5. 最终计算最小生成树
    long long mstWeight = xorMST(n, edges);
    answer += mstWeight;

    cout << answer << '\n';
    return 0;
}

